{
  "acts": [
    {
      "number": 1,
      "name": "The Warning Unheard",
      "summary": "Mira Vale discovers the flood watch bell is jammed during a routine check. She reports it to Reeve Tomas Kade, who dismisses the urgency because the river is calm and he fears panic. That night, the river wall cracks; Mira and retired mason Orin Pike see the leak and realize the lower ward is in danger. Tomas orders them not to act until morning.",
      "emotionalArc": "From calm routine to rising anxiety and frustration",
      "turningPoint": "Mira and Orin witness water seeping through the cracked river wall, but Tomas orders them to wait for daylight, forcing Mira to choose between obedience and action."
    },
    {
      "number": 2,
      "name": "The Race Against Water",
      "summary": "Mira and Orin defy Tomas and head to the old tower to fix the gear. They face obstacles: a collapsed bridge, a locked tower door, and a broken winch. At the midpoint, they think they've repaired the gear, but a false victory collapses when the jam returns due to a hidden flaw. Tomas catches up, arrests them for insubordination, but then the river surges, flooding the lower ward and causing irreversible damage—including the loss of Orin's old workshop.",
      "emotionalArc": "From defiant hope to despair and loss",
      "turningPoint": "The floodwaters destroy Orin's workshop, killing a trapped child (or pet) and proving that delay has deadly consequences, forcing Tomas to switch from antagonist to ally."
    },
    {
      "number": 3,
      "name": "The Sound That Saves",
      "summary": "With Tomas now helping, the trio races against the rising water to the tower. They must improvise a new gear part using Orin's tools and Mira's knowledge. In the climax, Mira must choose between perfect repair (which takes too long) and a risky temporary fix. She chooses the temporary fix, sounding the bell just in time to warn the lower ward. The flood crests but the evacuation succeeds. Tomas publicly admits his error, and Mira is hailed as a hero.",
      "emotionalArc": "From guilt and determination to bittersweet triumph",
      "turningPoint": "Mira decides to hammer the gear into place with a flawed part, knowing it will break afterward but will ring the bell now—a climactic choice that sacrifices perfection for saving lives."
    }
  ],
  "centralConflict": "Mira wants to sound the flood warning to save the lower ward vs. the broken bell mechanism, bureaucratic resistance, and the rising floodwater.",
  "theme": "Is it better to follow protocol or to act on instinct when lives are at stake?",
  "endingDirection": "Bittersweet victory: the ward is saved, but the cost of delay is felt; Mira's decision proves that imperfect action is better than perfect inaction."
}

